import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define optimized CUDA kernel for fused KL divergence with improved robustness
kl_div_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cooperative_groups.h>
#include <cooperative_groups/reduce.h>
#include <cuda_fp16.h>
#include <type_traits>

namespace cg = cooperative_groups;

template<typename scalar_t, typename compute_t>
__device__ compute_t safe_kl_compute(scalar_t p_val, scalar_t t_val) {
    // Explicit type conversion with validation
    const compute_t p = static_cast<compute_t>(p_val);
    const compute_t t = static_cast<compute_t>(t_val);

    // Use type-appropriate constants
    const compute_t zero = static_cast<compute_t>(0);
    const compute_t min_threshold = static_cast<compute_t>(1e-12);

    if (t > zero && p > min_threshold) {
        // Use appropriate math functions based on compute_t
        if constexpr (std::is_same<compute_t, float>::value) {
            return t * (__logf(t) - __logf(p));
        } else {
            return t * (log(t) - log(p));
        }
    }
    return zero;
}

template<typename scalar_t, typename compute_t = float>
__global__ void fused_kl_div_kernel_robust(
    const scalar_t* __restrict__ predictions,
    const scalar_t* __restrict__ targets,
    scalar_t* __restrict__ output,
    int batch_size,
    int seq_len
) {
    // Input validation at thread level
    if (batch_size <= 0 || seq_len <= 0) return;

    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    const scalar_t* pred_batch = predictions + batch_idx * seq_len;
    const scalar_t* target_batch = targets + batch_idx * seq_len;

    cg::thread_block block = cg::this_thread_block();
    cg::thread_block_tile<32> warp = cg::tiled_partition<32>(block);

    compute_t thread_sum = static_cast<compute_t>(0);

    int tid = threadIdx.x;
    int total_threads = blockDim.x;

    for (int idx = tid; idx < seq_len; idx += total_threads) {
        // Explicit, validated type conversion
        thread_sum += safe_kl_compute<scalar_t, compute_t>(
            pred_batch[idx], 
            target_batch[idx]
        );
    }

    // Warp reduction with explicit type handling
    compute_t warp_sum = cg::reduce(warp, thread_sum, cg::plus<compute_t>());

    __shared__ compute_t block_sums[32];
    if (warp.thread_rank() == 0) {
        block_sums[warp.meta_group_rank()] = warp_sum;
    }
    block.sync();

    if (warp.meta_group_rank() == 0) {
        compute_t block_sum = static_cast<compute_t>(0);
        int num_warps = (total_threads + 31) / 32;
        if (warp.thread_rank() < num_warps) {
            block_sum = block_sums[warp.thread_rank()];
        }

        compute_t final_sum = cg::reduce(warp, block_sum, cg::plus<compute_t>());

        if (warp.thread_rank() == 0) {
            // Final conversion with explicit cast
            output[batch_idx] = static_cast<scalar_t>(final_sum);
        }
    }
}

torch::Tensor fused_kl_div_cuda_robust(torch::Tensor predictions, torch::Tensor targets) {
    // Validate inputs before processing
    TORCH_CHECK(predictions.is_cuda(), "predictions must be a CUDA tensor");
    TORCH_CHECK(targets.is_cuda(), "targets must be a CUDA tensor");
    TORCH_CHECK(predictions.sizes() == targets.sizes(), "Input tensors must have same shape");
    TORCH_CHECK(predictions.dim() == 2, "Inputs must be 2D (batch, sequence)");

    predictions = predictions.contiguous();
    targets = targets.contiguous();

    auto batch_size = predictions.size(0);
    auto seq_len = predictions.size(1);

    auto output = torch::zeros({batch_size}, predictions.options());

    int threads = 256;
    int blocks = batch_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(predictions.scalar_type(), "fused_kl_div_kernel_robust", ([&] {
        // Use double precision for internal computation when inputs are double
        using compute_t = std::conditional_t<
            std::is_same<scalar_t, double>::value, 
            double, 
            float
        >;

        fused_kl_div_kernel_robust<scalar_t, compute_t><<<blocks, threads>>>(
            predictions.data_ptr<scalar_t>(),
            targets.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            seq_len
        );
    }));

    return output.mean();
}
"""

kl_div_cpp_source = """
torch::Tensor fused_kl_div_cuda_robust(torch::Tensor predictions, torch::Tensor targets);
"""

# Compile the inline CUDA code
fused_kl_div_robust = load_inline(
    name="fused_kl_div_robust",
    cpp_sources=kl_div_cpp_source,
    cuda_sources=kl_div_source,
    functions=["fused_kl_div_cuda_robust"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_cuda_cflags=["-O3", "--use_fast_math", "-std=c++17"],
)

class ModelNewRobust(nn.Module):
    def __init__(self):
        super(ModelNewRobust, self).__init__()
        self.fused_kl_div = fused_kl_div_robust

    def forward(self, predictions, targets):
        # Explicit type checking
        if predictions.dtype != torch.float32 and predictions.dtype != torch.float64:
            predictions = predictions.to(torch.float32)
            targets = targets.to(torch.float32)

        predictions = predictions.contiguous()
        targets = targets.contiguous()

        # Use consistent type for clamping
        dtype = predictions.dtype
        min_val = torch.tensor(1e-12, dtype=dtype, device=predictions.device)
        predictions = torch.clamp(predictions, min=min_val)
        targets = torch.clamp(targets, min=min_val)

        predictions = predictions / predictions.sum(dim=-1, keepdim=True)
        targets = targets / targets.sum(dim=-1, keepdim=True)

        return self.fused_kl_div.fused_kl_div_cuda_robust(predictions, targets)
